    counts[item.type] = (counts[item.type] || 0) + 1;
  });

  // Calculate total base premium with building blocks
  let totalBasePremium = 0;
  const processed: Set<string> = new Set();
  items.forEach((item: any) => {
    const type = item.type;
    if (processed.has(type)) return;
    processed.add(type);

    const count = counts[type];
    const base = basePremiums[type] || 0;

    // Apply building block for components: 3 alike = 60 G
    if (type === "rune" || type === "moonstone") {
      const blocks = Math.floor(count / 3);
      const remainder = count % 3;
      totalBasePremium += blocks * 60 + remainder * base;
    } else {
      totalBasePremium += count * base;
    }
  });

  return { results: [{ premium: totalBasePremium + 5 }] };
}

