export function processScenario(scenario: any): any {
  // Minimal implementation - handle cursed surcharge
  const items = scenario.steps[0].items;
  const basePremiums: Record<string, number> = { sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25 };

  // Count items by type for building block detection
  const counts: Record<string, number> = {};
  items.forEach((item: any) => {
    counts[item.type] = (counts[item.type] || 0) + 1;
  });

  // Calculate total base premium with building blocks and modifiers
  let totalBasePremium = 0;
  for (const type of Object.keys(counts)) {
    const count = counts[type];
    const base = basePremiums[type] || 0;

    // Apply building block for components: exactly 3 alike = 60 G
    if ((type === "rune" || type === "moonstone") && count === 3) {
      totalBasePremium += 60;
    } else {
      totalBasePremium += count * base;
    }
  }

  // Apply item-specific modifiers (cursed adds 50% to item's base premium)
  let itemModifiers = 0;
  items.forEach((item: any) => {
    if (item.cursed) {
      const base = basePremiums[item.type] || 0;
      // For components with building blocks, we need to check if it's part of a block
      if ((item.type === "rune" || item.type === "moonstone") && counts[item.type] === 3) {
        // The block premium is 60 for 3, so each item's share is 20
        itemModifiers += 20 * 0.5; // 50% of 20 = 10 per item in block
      } else {
        itemModifiers += base * 0.5;
      }
    }
  });

  const totalPremium = totalBasePremium + itemModifiers + 5;
  return { results: [{ premium: Math.ceil(totalPremium) }] };
}

